import { useState } from 'react';
import {
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Button,
  Tag,
  Intent,
  Alignment,
} from '@blueprintjs/core';

type LOD = 'MACRO' | 'MESO' | 'MICRO';

function App() {
  const [zoom, setZoom] = useState(1.0);

  // Compute LOD from zoom level
  const getLOD = (z: number): LOD => {
    if (z < 0.5) return 'MACRO';
    if (z > 2.0) return 'MICRO';
    return 'MESO';
  };

  const lod = getLOD(zoom);

  const getLODIntent = (l: LOD): Intent => {
    switch (l) {
      case 'MACRO': return Intent.WARNING;
      case 'MESO': return Intent.PRIMARY;
      case 'MICRO': return Intent.SUCCESS;
    }
  };

  const handleZoomIn = () => setZoom(z => Math.min(z * 1.5, 5.0));
  const handleZoomOut = () => setZoom(z => Math.max(z / 1.5, 0.1));
  const handleReset = () => setZoom(1.0);

  return (
    <div style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      <Navbar>
        <NavbarGroup align={Alignment.LEFT}>
          <NavbarHeading>MMS Canvas</NavbarHeading>
          <NavbarDivider />
          <span style={{ fontFamily: 'monospace' }}>
            Zoom: {zoom.toFixed(2)}x
          </span>
          <NavbarDivider />
          <Tag intent={getLODIntent(lod)} minimal>
            {lod}
          </Tag>
        </NavbarGroup>
        <NavbarGroup align={Alignment.RIGHT}>
          <Button icon="minus" minimal onClick={handleZoomOut} />
          <Button icon="plus" minimal onClick={handleZoomIn} />
          <NavbarDivider />
          <Button icon="reset" minimal onClick={handleReset}>
            Reset
          </Button>
        </NavbarGroup>
      </Navbar>

      <div style={{ flex: 1, display: 'flex' }}>
        {/* Sidebar placeholder */}
        <div style={{
          width: 120,
          borderRight: '1px solid #e1e8ed',
          padding: 10,
          backgroundColor: '#f5f8fa'
        }}>
          <div style={{ fontWeight: 600, marginBottom: 10 }}>Trains</div>
          {Array.from({ length: 10 }, (_, i) => (
            <div key={i} style={{ padding: '4px 0', fontSize: 12 }}>
              TRAIN-{String(i + 1).padStart(3, '0')}
            </div>
          ))}
        </div>

        {/* Canvas area placeholder */}
        <div style={{
          flex: 1,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          backgroundColor: '#f4f4f5',
          color: '#5c7080',
          fontSize: 14
        }}>
          R3F Canvas will render here (F102)
        </div>
      </div>
    </div>
  );
}

export default App;

# WebGL Performance Patterns for High-Density Planning Systems

Reference for building CAD/Google Earth-style applications in the browser with 50k+ objects.

Source: Expert patterns for systems like Figma, Google Maps, professional CAD tools.

---

## 1. GPU Data Patterns

### Data Textures (State as Texture)

**What:** Encode object state (color, status, conflict) in a `DataTexture` instead of CPU loops.

**Why:** Updating 50k object colors via CPU = 50k operations. Uploading a 256x256 texture = 1 operation.

**How:**
```javascript
// Create texture once
const data = new Uint8Array(width * height * 4); // RGBA
const texture = new DataTexture(data, width, height, RGBAFormat);

// Update state (CPU)
data[index * 4 + 0] = red;
data[index * 4 + 1] = green;
texture.needsUpdate = true;

// Read in shader (GPU)
vec4 state = texture2D(uStateTexture, vec2(instanceId / width, 0.0));
```

**Trigger:** When you have >1000 objects that need state updates per frame.

**Already in project:** MacroLayer heatmap uses this pattern.

---

### Struct of Arrays (SoA) vs Array of Structs (AoS)

**What:** Store data in parallel typed arrays instead of object arrays.

**Why:**
- Cache-friendly memory access
- Direct upload to GPU buffers
- No GC pressure from object allocation

**Example:**
```javascript
// AoS (bad for GPU)
const tasks = [{ id: 1, x: 10, y: 20 }, { id: 2, x: 15, y: 25 }];

// SoA (GPU-friendly)
const ids = new Uint32Array([1, 2]);
const positions = new Float32Array([10, 20, 15, 25]); // x1,y1,x2,y2
```

**Trigger:** When JSON parsing or array operations become bottleneck (profile first).

**Note:** Adds complexity. Only use when measured performance requires it.

---

## 2. Picking & Interaction

### Math-Based Picking (O(1) vs Raycaster O(N))

**What:** For grid-based layouts (Gantt, timeline), calculate hit directly from mouse position.

**Why:** Three.js Raycaster checks every object. Math is instant.

**How:**
```javascript
// For time-based grid
const day = Math.floor((mouseX / zoom) + offsetX) / DAY_WIDTH;
const train = Math.floor((mouseY / zoom) + offsetY) / ROW_HEIGHT;
const taskId = lookupGrid[train][day]; // O(1)
```

**Trigger:** When hover/click feels sluggish with many objects.

**Already in project:** MesoLayer uses Spatial Hash Grid for this.

---

### Spatial Hash Grid

**What:** Divide space into cells, store object references per cell.

**How:**
```javascript
const cellSize = 50; // pixels
const grid = new Map();

function addToGrid(obj) {
  const key = `${Math.floor(obj.x / cellSize)}_${Math.floor(obj.y / cellSize)}`;
  if (!grid.has(key)) grid.set(key, []);
  grid.get(key).push(obj);
}

function queryPoint(x, y) {
  const key = `${Math.floor(x / cellSize)}_${Math.floor(y / cellSize)}`;
  return grid.get(key) || [];
}
```

**Trigger:** When you need fast spatial queries (hover detection, collision).

---

### Pointer Events Layering

**What:** Control which layer receives mouse events.

**Why:** HTML overlays steal events from canvas underneath.

**How:**
```css
.overlay-container { pointer-events: none; }
.overlay-container .clickable-card { pointer-events: auto; }
```

**Trigger:** When clicks don't reach the canvas, or tooltips block interaction.

---

## 3. LOD (Level of Detail) Transitions

### Hysteresis (Dead Zone)

**What:** Use different thresholds for entering vs leaving a LOD level.

**Why:** Without it, user zooming near threshold causes flickering.

**How:**
```javascript
// Bad: flickers at exactly 0.5
const lod = zoom > 0.5 ? 'meso' : 'macro';

// Good: stable transition
let currentLod = 'macro';
if (currentLod === 'macro' && zoom > 0.55) currentLod = 'meso';
if (currentLod === 'meso' && zoom < 0.45) currentLod = 'macro';
```

**Trigger:** Implement from the start when building LOD systems.

---

### Opacity Crossfade

**What:** Fade between LOD layers instead of hard switch.

**How:**
```javascript
const t = smoothstep(0.45, 0.55, zoom);
macroLayer.opacity = 1 - t;
mesoLayer.opacity = t;
```

**Trigger:** When LOD transitions feel jarring.

---

## 4. React + WebGL Performance

### React-Free Zone

**What:** Bypass React for 60fps operations.

**Why:** useState triggers re-render. At 60fps = 60 re-renders/second = death.

**How:**
```javascript
// Bad: React re-renders 60x/sec
const [position, setPosition] = useState({ x: 0, y: 0 });
useFrame(() => setPosition({ x: mouse.x, y: mouse.y }));

// Good: Direct mutation, no re-render
const positionRef = useRef({ x: 0, y: 0 });
useFrame(() => {
  positionRef.current.x = mouse.x;
  mesh.current.position.x = positionRef.current.x;
});
```

**Trigger:** Any animation or continuous interaction (drag, pan, zoom, hover highlight).

---

### Object Pooling (GC Avoidance)

**What:** Reuse objects instead of creating new ones in hot paths.

**Why:** `new Vector3()` in useFrame = 60 allocations/sec = GC stutters.

**How:**
```javascript
// Bad: creates garbage
useFrame(() => {
  const temp = new Vector3(x, y, z);
  mesh.position.copy(temp);
});

// Good: reuse
const temp = useMemo(() => new Vector3(), []);
useFrame(() => {
  temp.set(x, y, z);
  mesh.position.copy(temp);
});
```

**Trigger:** Any code inside useFrame, event handlers, or animation loops.

---

## 5. Numerical Precision

### Local Coordinates

**What:** Subtract a global offset from large numbers before sending to GPU.

**Why:** Float32 has ~7 digits precision. Unix timestamp (1700000000000) overflows.

**How:**
```javascript
const EPOCH = new Date('2024-01-01').getTime();

// CPU: convert to local
const localTime = (task.timestamp - EPOCH) / MS_PER_DAY; // small number

// Send to shader
uniforms.uTime.value = localTime;
```

**Trigger:** When objects wobble or disappear at high zoom. When using timestamps in shaders.

---

### Z-Fighting Prevention

**What:** Add micro-offset to Z position for overlapping planes.

**Why:** Same Z + depth buffer = flickering.

**How:**
```javascript
// In 2D orthographic view
mesh.position.z = layerIndex * 0.001;
// or
mesh.renderOrder = layerIndex;
```

**Trigger:** When overlapping elements flicker.

---

## 6. Loading & Data

### Progressive Loading

**What:** Load visible data first, fetch more on demand.

**Why:** 10 years of detailed data = huge payload. User sees 1 month at a time.

**Pattern:**
```
1. Load viewport + buffer (current view ± 20%)
2. On pan/zoom, fetch missing chunks
3. Macro view = aggregated data (small)
4. Micro view = detailed data (load on demand)
```

**Trigger:** When initial load is slow or payload > 1MB.

---

### Virtualización Lógica

**What:** Only process visible data range, not entire dataset.

**How:**
```javascript
const visibleStart = Math.floor(cameraX / DAY_WIDTH);
const visibleEnd = Math.ceil((cameraX + viewportWidth) / DAY_WIDTH);

// Only iterate visible range
for (let i = visibleStart; i < visibleEnd; i++) {
  renderTask(tasks[i]);
}
```

**Trigger:** When you have 10+ years of data but show weeks at a time.

---

## 7. Debugging Tools

### stats.gl

**What:** Performance monitor showing FPS, draw calls, triangles, GPU memory.

**Why:** stats.js only shows FPS. You need to know WHY it's slow.

**Install:** `npm install stats.gl`

---

### Spector.js

**What:** Chrome extension that captures WebGL frames.

**Why:** Shows exactly what GPU drew, shader by shader. Essential for "why is this invisible?" bugs.

**Install:** Chrome Web Store → Spector.js

---

### Leva

**What:** Runtime GUI for tweaking values.

**Why:** Change colors, thresholds, sizes without code reload.

**Use:** During development, expose magic numbers as Leva controls.

---

### Debug Render Mode

**What:** Alternate coloring that shows render cost or instance index.

**Why:** Visually identifies objects being rendered that shouldn't be (offscreen, hidden).

**How:**
```javascript
// Toggle with Alt+D
if (debugMode) {
  color = instanceIndex / totalInstances; // gradient by index
  // or
  color = isOffscreen ? RED : GREEN;
}
```

**Trigger:** When FPS is low but you don't know what's causing it.

---

## 8. UX Patterns

### Ghost Drag

**What:** Show semi-transparent copy during drag, keep original in place.

**Why:** User sees immediate feedback + can cancel safely.

**Trigger:** When implementing drag-and-drop for task rescheduling.

---

### Scroll Sync (Canvas as Source)

**What:** WebGL camera position drives HTML sidebar scroll, not vice versa.

**Why:** Canvas animation is smoother. HTML following canvas = smooth. Canvas following HTML = janky.

**How:**
```javascript
// In animation loop
sidebarElement.style.transform = `translateY(${-cameraY * PX_PER_TRAIN}px)`;
```

**Already in project:** Implemented in TrainList.tsx

---

## 9. Shader Patterns

### Shader Warm-up

**What:** Force shader compilation before user interaction.

**Why:** First render with new shader = compilation jank (freeze).

**How:**
```javascript
// Before showing UI
renderer.compile(scene, camera);
// or render one invisible frame
```

**Trigger:** When first interaction causes visible freeze.

---

### Discard vs Alpha

**What:** In fragment shader, `discard` vs `alpha = 0.0`.

**Why:** `discard` removes from depth buffer (good for holes). Alpha keeps in buffer.

**Trigger:** When transparent objects behave unexpectedly with depth.

---

## Quick Reference: When to Apply

| Symptom | Pattern to Apply |
|---------|------------------|
| Slow state updates (color changes) | Data Textures |
| Slow hover/click detection | Math Picking / Spatial Hash |
| LOD transition flickers | Hysteresis + Crossfade |
| Animation stutters | React-Free Zone + Object Pooling |
| Objects wobble at high zoom | Local Coordinates |
| Overlapping elements flicker | Z-Fighting prevention |
| Initial load slow | Progressive Loading |
| FPS low, unknown cause | Debug Render Mode + stats.gl |
| Clicks not reaching canvas | Pointer Events layering |

# @belt/toolkit

A TypeScript utility library providing runtime type validation with full type inference, state management, and common helpers.

## Installation

```bash
pnpm add @belt/toolkit
```

## Quick Start

```typescript
import { createType, createModel, createMachine, createSlice, ms, invariant } from '@belt/toolkit';

// Define a validated type with full TypeScript inference
const UserSchema = createModel({
  id: 'number',
  name: 'string',
  email: 'string?',
  roles: 'string[]',
});

// Parse and validate data
const user = UserSchema.parse(data); // Throws if invalid
```

---

## Schema System

Runtime type validation with compile-time TypeScript inference.

### createType / createModel

```typescript
import { createType, createModel, InferType } from '@belt/toolkit';

// String-based definition
const StringType = createType('string');
const NumberArrayType = createType('number[]');
const OptionalStringType = createType('string?');

// Object schema with createModel (shorthand)
const UserSchema = createModel({
  id: 'number',
  name: 'string',
  email: 'string?',
});

// Equivalent using createType
const UserSchema2 = createType({
  properties: {
    id: 'number',
    name: 'string',
    email: 'string?',
  },
});

// Get TypeScript type from schema
type User = InferType<typeof UserSchema>;
// => { id: number; name: string; email?: string }
```

### Type Definitions

#### Primitive Types

| Definition | TypeScript Type | Description |
|------------|-----------------|-------------|
| `'string'` | `string` | String values |
| `'number'` | `number` | Numeric values (rejects NaN) |
| `'boolean'` | `boolean` | Boolean values |
| `'null'` | `null` | Null only |
| `'undefined'` | `undefined` | Undefined only |
| `'date'` | `Date` | Valid Date objects |
| `'function'` | `Function` | Any function |
| `'object'` | `object` | Plain objects |
| `'unknown'` | `unknown` | Any value (no validation) |
| `'any'` | `any` | Any value (no validation) |

#### Modifiers

| Modifier | Example | Result |
|----------|---------|--------|
| `?` (optional) | `'string?'` | `string \| undefined` |
| `[]` (array) | `'string[]'` | `string[]` |
| `[]?` (optional array) | `'string[]?'` | `string[] \| undefined` |

#### Object Definitions

```typescript
// Object with properties
createType({
  properties: {
    name: 'string',
    age: 'number',
    email: 'string?', // optional
  },
});

// Nested objects
createType({
  properties: {
    user: {
      properties: {
        name: 'string',
        address: {
          properties: {
            city: 'string',
            zip: 'string',
          },
        },
      },
    },
  },
});
```

#### Enum Definitions

```typescript
import { stringEnum } from '@belt/toolkit';

// Using stringEnum helper (recommended)
const StatusValues = stringEnum('pending', 'active', 'completed');
const StatusSchema = createType({ enum: StatusValues });

// Inline (requires 'as const')
const StatusSchema2 = createType({
  enum: ['pending', 'active', 'completed'] as const,
});

type Status = InferType<typeof StatusSchema>; // => 'pending' | 'active' | 'completed'
```

#### Union Definitions

```typescript
// Union of primitives
const StringOrNumber = createType({
  union: ['string', 'number'],
});

// Nullable type
const NullableString = createType({
  union: ['string', 'null'],
});

type Result = InferType<typeof StringOrNumber>; // => string | number
```

#### Array Definitions

```typescript
// Simple array (string shorthand)
const StringArray = createType('string[]');

// Array with items syntax
const StringArray2 = createType({ items: 'string' });

// Array of objects
const UserList = createType({
  items: {
    properties: {
      id: 'number',
      name: 'string',
    },
  },
});

// Using .list() method
const UserSchema = createModel({ id: 'number', name: 'string' });
const UserListSchema = UserSchema.list();
```

#### Record Definitions

```typescript
// Record<string, T>
const StringRecord = createType({ record: 'string' });
const NumberRecord = createType({ record: 'number' });

type Dict = InferType<typeof StringRecord>; // => Record<string, string>
```

### Schema Methods

```typescript
const Schema = createModel({
  id: 'number',
  name: 'string',
});

// .parse(value, path?) - Validate and return typed value, throws on error
const user = Schema.parse({ id: 1, name: 'John' });

// Parse from nested path
const user2 = Schema.parse(apiResponse, 'data.user');

// .parseList(value, path?) - Parse array of items
const users = Schema.parseList([{ id: 1, name: 'John' }]);

// .isValid(value) - Type guard, returns boolean
if (Schema.isValid(data)) {
  // data is typed as { id: number; name: string }
}

// .list() - Get array schema (cached)
const ListSchema = Schema.list();
```

### Helper Functions

```typescript
import { isType, invariantType } from '@belt/toolkit';

// isType - Type guard
const value: unknown = getData();
if (isType(value, 'string')) {
  // value is string
}
if (isType(value, 'date')) {
  // value is Date
}

// invariantType - Assert or throw
function processUser(data: unknown) {
  invariantType('object', data);
  // data is now typed as object
}

// Custom error message with placeholders
invariantType('string', value, processUser,
  'Expected $definition but got $typename: $originalMessage'
);
```

### Type Inference

```typescript
import { InferType, Type } from '@belt/toolkit';

const Schema = createModel({
  id: 'number',
  name: 'string',
  status: { enum: ['active', 'inactive'] as const },
  tags: 'string[]',
  metadata: 'object?',
});

// Extract TypeScript type
type MyType = InferType<typeof Schema>;
// => {
//   id: number;
//   name: string;
//   status: 'active' | 'inactive';
//   tags: string[];
//   metadata?: object;
// }

// Schema types are cached for string definitions
const a = createType('string');
const b = createType('string');
console.log(a === b); // true
```

---

## State Machine

Redux-like state management with slices, caching, and React hooks.

### createMachine

```typescript
import { createMachine, createSlice, createAsyncSlice } from '@belt/toolkit';

const machine = createMachine({
  id: 'app',
  slices: {
    counter: createSlice({
      id: 'counter',
      initial: { count: 0 },
      cache: 'session',
      reducers: {
        increment: (draft) => { draft.count += 1; },
        decrement: (draft) => { draft.count -= 1; },
        set: (draft, value: number) => { draft.count = value; },
      },
    }),
    user: createAsyncSlice({
      id: 'user',
      cache: 'user',
      context: { userID: '' },
      load: async (ctx) => {
        const res = await fetch(`/api/users/${ctx.userID}`);
        return res.json();
      },
    }),
  },
  selectors: {
    doubleCount: (state) => state.counter.count * 2,
  },
  context: { userID: 'user-123' },
});
```

### createSlice (Sync)

```typescript
const counterSlice = createSlice({
  id: 'counter',
  initial: { count: 0, history: [] as number[] },
  cache: 'session', // 'session' | 'user' | 'global'
  reducers: {
    // Reducers receive Immer draft - mutate directly
    increment: (draft) => {
      draft.count += 1;
    },
    add: (draft, amount: number) => {
      draft.count += amount;
      draft.history.push(draft.count);
    },
    reset: (draft) => {
      draft.count = 0;
      draft.history = [];
    },
  },
});
```

### createAsyncSlice

```typescript
const usersSlice = createAsyncSlice({
  id: 'users',
  cache: 'session',
  context: { page: 1 }, // Required context for load function
  initial: { value: [], loading: false }, // Optional initial override
  load: async (context) => {
    const response = await fetch(`/api/users?page=${context.page}`);
    return response.json();
  },
});

// Async slices automatically generate these actions:
// - load: Start loading (sets loading=true)
// - success: Set value on success
// - fail: Set error on failure
// - clear: Reset to initial state
```

### Async Slice State Shape

```typescript
type AsyncSliceState<T> = {
  loading: boolean;
  loaded: boolean;
  failed: boolean;
  error: string | null;
  value: T | null;
  changes: number;
};
```

### Cache Strategies

| Strategy | Description |
|----------|-------------|
| `'session'` | Invalidate when sessionID changes |
| `'user'` | Invalidate when userID changes |
| `'global'` | Never automatically invalidate |

### Machine API

```typescript
const machine = createMachine({ id: 'app', slices: { ... } });

// Dispatch actions
machine.dispatch(machine.actions.counter.increment());
machine.dispatch(machine.actions.counter.add(5));

// Get current state
const state = machine.getState();

// Subscribe to changes
const unsubscribe = machine.subscribe((state, prevState) => {
  console.log('State changed:', state);
});

// Reset to initial state
machine.reset();

// Access action creators and types
machine.actions.counter.increment(); // => { type: '@app/counter/increment', payload: undefined }
machine.actionTypes.counter.increment; // => '@app/counter/increment'

// Context management
machine.getContext(); // => { userID: 'user-123' }
machine.provideContext({ userID: 'new-user' });

// Direct reducer access (for Redux integration)
const rootReducer = machine.reducer;
```

