### Other Utilities

```typescript
import {
  getTypeOf,
  maskData,
  delay,
  createProxy,
  formatDate,
  setDefaultDateLocale,
  getDefaultDateLocale,
  EMPTY
} from '@belt/toolkit';

// getTypeOf - Get readable type name
getTypeOf(null);          // 'Null'
